-const ROOT_DIR = join(import.meta.dirname, "..");
-const DB_PATH = join(ROOT_DIR, "index", "memory.db");
-const REPORT_PATH = join(ROOT_DIR, "brain", `_dedup-report-${today()}.md`);
-
-function jaccard(a: string, b: string): number {
-  const setA = new Set(a.toLowerCase().split(/\s+/).filter(Boolean));
-  const setB = new Set(b.toLowerCase().split(/\s+/).filter(Boolean));
-  if (setA.size === 0 && setB.size === 0) return 1;
-  const intersection = new Set([...setA].filter(x => setB.has(x)));
-  const union = new Set([...setA, ...setB]);
-  return intersection.size / union.size;
-}
-
-function extractBullets(content: string): string[] {
-  const bullets: string[] = [];
-  for (const line of content.split("\n")) {
-    const trimmed = line.trim();
-    if (trimmed.startsWith("- ") && trimmed.length > 10) {
-      bullets.push(trimmed.slice(2));
-    }
-  }
-  return bullets;
-}
-
-async function dedup(): Promise<DedupReport> {
-  const store = new BrainStore(DB_PATH);
-  const files = await scanBrainFiles();
-
-  const duplicates: DedupReport["duplicates"] = [];
-
-  // 1. Check exact duplicate bullets across files
-  const bulletMap = new Map<string, string[]>(); // bullet text → file paths
-  for (const file of files) {
-    const bullets = extractBullets(file.content);
-    for (const bullet of bullets) {
-      const existing = bulletMap.get(bullet.toLowerCase());
-      if (existing) {
-        existing.push(file.path);
-      } else {
-        bulletMap.set(bullet.toLowerCase(), [file.path]);
-      }
-    }
-  }
-
-  for (const [, paths] of bulletMap) {
-    if (paths.length > 1) {
-      duplicates.push({
-        type: "exact",
-        files: paths,
-        excerpt: paths[0], // the duplicate content
-        suggestion: `Merge these files or remove duplicates. Same fact stored in ${paths.length} places.`,
-      });
-    }
-  }
-
-  // 2. Check near-duplicate paragraphs (Jaccard ≥ 0.8)
-  for (let i = 0; i < files.length; i++) {
-    for (let j = i + 1; j < files.length; j++) {
-      const bulletsA = extractBullets(files[i].content);
-      const bulletsB = extractBullets(files[j].content);
-
-      for (const bulletA of bulletsA) {
-        for (const bulletB of bulletsB) {
-          if (jaccard(bulletA, bulletB) >= 0.8 && bulletA !== bulletB) {
-            duplicates.push({
-              type: "near",
-              files: [files[i].path, files[j].path],
-              excerpt: `${bulletA.slice(0, 80)}... ≈ ${bulletB.slice(0, 80)}...`,
-              suggestion: "These are near-duplicates. Keep the more precise version.",
-            });
-          }
-        }
-      }
-    }
-  }
-
-  // 3. Check for stale entries (unchanged for 90+ days, might be outdated)
-  const ninetyDaysAgo = new Date();
-  ninetyDaysAgo.setDate(ninetyDaysAgo.getDate() - 90);
-  const staleThreshold = ninetyDaysAgo.toISOString().slice(0, 10);
-
-  const staleFiles = files.filter(f => {
-    const updated = f.frontmatter.updated || f.frontmatter.date || "";
-    return updated && updated < staleThreshold;
-  });
-
-  for (const file of staleFiles) {
-    duplicates.push({
-      type: "stale",
-      files: [file.path],
-      excerpt: `Last updated: ${file.frontmatter.updated || "unknown"}`,
-      suggestion: "This file hasn't been updated in 90+ days. Review for accuracy.",
-    });
-  }
-
-  // 4. Check for conflicts (contradictory facts) — basic check
-  // Look for "prefers X" vs "prefers Y" patterns
-  const preferences = new Map<string, string[]>();
-  for (const file of files) {
-    const bullets = extractBullets(file.content);
-    for (const bullet of bullets) {
-      const match = bullet.match(/(?:prefers?|uses?|loves?|hates?)\s+(.+)/i);
-      if (match) {
-        const key = match[0].toLowerCase().replace(/\s+/g, " ").trim();
-        const existing = preferences.get(key.split(/\s+/).slice(0, 3).join(" "));
-        if (existing) {
-          existing.push(`${file.path}: ${bullet}`);
-        } else {
-          preferences.set(key.split(/\s+/).slice(0, 3).join(" "), [`${file.path}: ${bullet}`]);
-        }
-      }
-    }
-  }
-
-  for (const [, entries] of preferences) {
-    if (entries.length > 1) {
-      const unique = [...new Set(entries.map(e => e.split(": ").slice(1).join(": ")))];
-      if (unique.length > 1) {
-        duplicates.push({
-          type: "conflict",
-          files: entries.map(e => e.split(": ")[0]),
-          excerpt: unique.join(" vs. "),
-          suggestion: "Possible conflict — resolve which is correct, or add context.",
-        });
-      }
-    }
-  }
-
-  store.close();
-
-  return {
-    duplicates: duplicates.slice(0, 100), // cap
-    stats: {
-      totalEntries: files.length,
-      duplicateGroups: duplicates.filter(d => d.type === "exact" || d.type === "near").length,
-      staleEntries: staleFiles.length,
-      conflicts: duplicates.filter(d => d.type === "conflict").length,
-    },
-  };
-}
-
-function formatReport(report: DedupReport): string {
-  let md = `# Dedup Report — ${today()}\n\n`;
-  md += `## Stats\n\n`;
-  md += `- Total entries: ${report.stats.totalEntries}\n`;
-  md += `- Duplicate groups: ${report.stats.duplicateGroups}\n`;
-  md += `- Stale entries: ${report.stats.staleEntries}\n`;
-  md += `- Conflicts: ${report.stats.conflicts}\n\n`;
-
-  if (report.duplicates.length === 0) {
-    md += `✅ No issues found! Brain is clean.\n`;
-    return md;
-  }
-
-  md += `## Issues\n\n`;
-
-  const byType = {
-    exact: report.duplicates.filter(d => d.type === "exact"),
-    near: report.duplicates.filter(d => d.type === "near"),
-    stale: report.duplicates.filter(d => d.type === "stale"),
-    conflict: report.duplicates.filter(d => d.type === "conflict"),
-  };
-
-  for (const [type, items] of Object.entries(byType)) {
-    if (items.length === 0) continue;
-    md += `### ${type.charAt(0).toUpperCase() + type.slice(1)} (${items.length})\n\n`;
-    for (const item of items.slice(0, 20)) {
-      md += `- **Files**: ${item.files.join(", ")}\n`;
-      md += `  - ${item.excerpt.slice(0, 120)}\n`;
-      md += `  - Suggestion: ${item.suggestion}\n\n`;
-    }
-  }
-
-  return md;
-}
-
-async function main(): Promise<void> {
-  console.log("Scanning brain for duplicates, stale entries, and conflicts...");
-  const report = await dedup();
-  const reportMd = formatReport(report);
-
-  writeFileSync(REPORT_PATH, reportMd, "utf-8");
-  console.log(`Report saved to ${REPORT_PATH}`);
-  console.log(`\n${reportMd}`);
-}
-
-main().catch(err => {
-  console.error("dedup failed:", err);
-  process.exit(1);
-});
